static inline float traverse_tree(int tree_id, const float* x) {
    const OptTree* tree = &TREES[tree_id];
    uint32_t idx = tree->start_idx;
    while (idx < tree->start_idx + tree->node_count) {
        const OptNode* node = &NODES[idx];
        if (node->is_leaf) return SHARED_LEAVES[node->u.leaf_idx];
        float t = decode_threshold(node->u.internal.threshold_q);
        idx = tree->start_idx + (x[node->u.internal.feature] < t
              ? node->u.internal.left : node->u.internal.right);
    }
    return 0.0f;
}
float predict(const float* x) {
    float s = 0.000000f;
    for (int i = 0; i < N_TREES; i++) s += traverse_tree(i, x);
    return s;
}

